function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const [active, setActive] = useState("home");

  useEffect(() => {
    const onScroll = () => {
      setScrolled(window.scrollY > 20);
      const sections = ["home", "about", "programs"];
      for (let s of [...sections].reverse()) {
        const el = document.getElementById(s);
        if (el && window.scrollY >= el.offsetTop - 100) { setActive(s); break; }
      }
    };
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const scrollTo = (id) => {
    document.getElementById(id)?.scrollIntoView({ behavior: "smooth" });
    setMobileOpen(false);
  };

  const navLinks = [
    { label: "Home", id: "home" },
    { label: "About Us", id: "about" },
    { label: "Programs & Activities", id: "programs" },
  ];

  return (
    <nav style={{
      position: "fixed", top: 0, left: 0, right: 0, zIndex: 1000,
      background: "#fff",
      boxShadow: scrolled ? "0 2px 20px rgba(0,0,0,0.08)" : "none",
      transition: "box-shadow 0.3s",
    }}>
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "0 24px", display: "flex", alignItems: "center", justifyContent: "space-between", height: 70 }}>
        <Logo />
        <div style={{ display: "flex", alignItems: "center", gap: 32 }} className="desktop-nav">
          {navLinks.map(l => (
            <button key={l.id} onClick={() => scrollTo(l.id)} style={{
              background: "none", border: "none", cursor: "pointer",
              fontFamily: "\'Nunito\', sans-serif", fontWeight: 700, fontSize: 15,
              color: active === l.id ? COLORS.primary : COLORS.dark,
              borderBottom: active === l.id ? `2px solid ${COLORS.primary}` : "2px solid transparent",
              paddingBottom: 2, transition: "all 0.2s",
            }}>{l.label}</button>
          ))}
          <button onClick={() => scrollTo("enquiry")} style={{
            background: COLORS.primary, color: "#fff", border: "none",
            borderRadius: 50, padding: "10px 24px", fontFamily: "\'Nunito\', sans-serif",
            fontWeight: 700, fontSize: 14, cursor: "pointer", transition: "transform 0.2s, box-shadow 0.2s",
            boxShadow: "0 4px 12px rgba(255,107,53,0.35)",
          }}
            onMouseEnter={e => { e.target.style.transform = "translateY(-2px)"; e.target.style.boxShadow = "0 6px 16px rgba(255,107,53,0.45)"; }}
            onMouseLeave={e => { e.target.style.transform = ""; e.target.style.boxShadow = "0 4px 12px rgba(255,107,53,0.35)"; }}
          >Enquire Now</button>
        </div>
        <button onClick={() => setMobileOpen(!mobileOpen)} className="hamburger" style={{
          display: "none", background: "none", border: "none", cursor: "pointer", flexDirection: "column", gap: 5, padding: 8,
        }}>
          {[0,1,2].map(i => <div key={i} style={{ width: 24, height: 2.5, background: COLORS.primary, borderRadius: 2 }} />)}
        </button>
      </div>
      {mobileOpen && (
        <div style={{ background: "#fff", borderTop: "1px solid #f0f0f0", padding: "16px 24px 24px" }}>
          {navLinks.map(l => (
            <button key={l.id} onClick={() => scrollTo(l.id)} style={{
              display: "block", width: "100%", textAlign: "left", background: "none", border: "none",
              fontFamily: "\'Nunito\', sans-serif", fontWeight: 700, fontSize: 16, color: COLORS.dark,
              padding: "12px 0", borderBottom: "1px solid #f5f5f5", cursor: "pointer",
            }}>{l.label}</button>
          ))}
          <button onClick={() => scrollTo("enquiry")} style={{
            marginTop: 16, width: "100%", background: COLORS.primary, color: "#fff", border: "none",
            borderRadius: 50, padding: "12px", fontFamily: "\'Nunito\', sans-serif", fontWeight: 700, fontSize: 15, cursor: "pointer",
          }}>Enquire Now</button>
        </div>
      )}
      <style>{`
        @import url(\'https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800;900&family=Inter:wght@400;500;600&display=swap\');
        @media (max-width: 768px) { .desktop-nav { display: none !important; } .hamburger { display: flex !important; } }
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { background: ${COLORS.bg}; }
        input, select, textarea { outline: none; }
        input:focus, select:focus, textarea:focus { border-color: ${COLORS.primary} !important; box-shadow: 0 0 0 3px rgba(255,107,53,0.12); }
      `}</style>
    </nav>
  );
}

function EnquiryForm({ compact = false }) {
  const [form, setForm] = useState({ parentName: "", childName: "", dob: "", phone: "", program: "", message: "" });
  const [submitted, setSubmitted] = useState(false);
  const [error, setError] = useState("");

  const SHEET_URL = "https://script.google.com/macros/s/AKfycbyOm2Wrgx3q_bv6OGZoAVp17sRDPCafgdn7YtM-61qDFjURqZHiyesbwoRVjgHyNrHKdA/exec";

  const handleSubmit = async () => {
    // Basic validation
    if (!form.parentName.trim() || !form.phone.trim()) {
      setError("Please fill in at least Parent Name and Phone Number.");
      setTimeout(() => setError(""), 3500);
      return;
    }

    // Format DOB nicely: 2026-03-07 → 07 March 2026
    const formatDob = (dob) => {
      if (!dob) return "—";
      const d = new Date(dob);
      return d.toLocaleDateString("en-IN", { day: "2-digit", month: "long", year: "numeric" });
    };

    const formattedDob = formatDob(form.dob);

    // 1. Send to Google Sheets + trigger email
    // Using dynamic script tag — fully bypasses CORS, works with Google Apps Script
    try {
      const params = new URLSearchParams({
        parentName: form.parentName,
        childName: form.childName || "—",
        dob: formattedDob,
        phone: form.phone,
        program: form.program || "—",
        message: form.message || "—",
      });
      const script = document.createElement("script");
      script.src = SHEET_URL + "?" + params.toString();
      document.body.appendChild(script);
      setTimeout(() => document.body.removeChild(script), 5000);
    } catch (err) {
      console.error("Sheet/email error:", err);
    }

    // 2. Open WhatsApp with pre-filled message
    const msg = [
      "🎉 Got new enquiry from parents",
      "",
      `Parent Name   : ${form.parentName}`,
      `Child's Name  : ${form.childName || "—"}`,
      `Date of Birth : ${formattedDob}`,
      `Phone Number  : ${form.phone}`,
      `Program       : ${form.program || "—"}`,
      form.message ? `Message       : ${form.message}` : "",
    ].filter(Boolean).join("\n");

    const encoded = encodeURIComponent(msg);
    window.open(`https://wa.me/919136906129?text=${encoded}`, "_blank");

    // 3. Show success, reset form
    setSubmitted(true);
    setTimeout(() => setSubmitted(false), 4000);
    setForm({ parentName: "", childName: "", dob: "", phone: "", program: "", message: "" });
  };

  const inputStyle = {
    width: "100%", padding: "11px 14px", borderRadius: 10, border: "1.5px solid #eee",
    fontFamily: "\'Inter\', sans-serif", fontSize: 14, color: COLORS.dark, background: "#fafafa",
    transition: "border-color 0.2s, box-shadow 0.2s", marginBottom: 10,
  };

  return (
    <div style={{ position: "relative" }}>
      {submitted && (
        <div style={{
          position: "absolute", top: -54, left: 0, right: 0,
          background: COLORS.accent, color: "#fff", borderRadius: 10, padding: "12px 20px",
          fontFamily: "\'Nunito\', sans-serif", fontWeight: 700, fontSize: 14, textAlign: "center",
          animation: "fadeIn 0.3s ease", zIndex: 10,
        }}>✅ Enquiry sent! We will call you within 24 hours.</div>
      )}
      {error && (
        <div style={{
          position: "absolute", top: -54, left: 0, right: 0,
          background: "#E74C3C", color: "#fff", borderRadius: 10, padding: "12px 20px",
          fontFamily: "\'Nunito\', sans-serif", fontWeight: 700, fontSize: 14, textAlign: "center",
          animation: "fadeIn 0.3s ease", zIndex: 10,
        }}>⚠️ {error}</div>
      )}
      <input value={form.parentName} onChange={e => setForm({ ...form, parentName: e.target.value })} placeholder="Parent Name" style={inputStyle} />
      <input value={form.childName} onChange={e => setForm({ ...form, childName: e.target.value })} placeholder="Child's Name" style={inputStyle} />
      <div style={{ position: "relative", marginBottom: 10 }}>
        {!form.dob && (
          <div style={{ position: "absolute", top: "50%", left: 14, transform: "translateY(-50%)", fontFamily: "'Inter', sans-serif", fontSize: 14, color: "#999", pointerEvents: "none", zIndex: 1 }}>
            Child's Date of Birth
          </div>
        )}
        <input type="date" value={form.dob} onChange={e => setForm({ ...form, dob: e.target.value })} style={{ ...inputStyle, marginBottom: 0, color: form.dob ? COLORS.dark : "transparent", width: "100%" }} />
      </div>
      <input type="tel" value={form.phone} onChange={e => setForm({ ...form, phone: e.target.value })} placeholder="Phone Number" style={inputStyle} />
      <select value={form.program} onChange={e => setForm({ ...form, program: e.target.value })} style={{ ...inputStyle, color: form.program ? COLORS.dark : "#999" }}>
        <option value="">Preferred Program</option>
        <option>Playgroup (1.5–2.5 yrs)</option>
        <option>Nursery (2.5–3.5 yrs)</option>
        <option>Jr KG (3.5–4.5 yrs)</option>
        <option>Sr KG (4.5–5.5 yrs)</option>
      </select>
      {!compact && <textarea value={form.message} onChange={e => setForm({ ...form, message: e.target.value })} placeholder="Any questions for us?" rows={3} style={{ ...inputStyle, resize: "vertical", fontFamily: "\'Inter\', sans-serif" }} />}
      <button onClick={handleSubmit} style={{
        width: "100%", padding: "13px", background: COLORS.primary, color: "#fff",
        border: "none", borderRadius: 10, fontFamily: "\'Nunito\', sans-serif", fontWeight: 800,
        fontSize: 15, cursor: "pointer", transition: "transform 0.2s, box-shadow 0.2s",
        boxShadow: "0 4px 14px rgba(255,107,53,0.4)",
      }}
        onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-2px)"; }}
        onMouseLeave={e => { e.currentTarget.style.transform = ""; }}
      >Send Enquiry 🚀</button>
      <style>{`@keyframes fadeIn { from { opacity:0; transform:translateY(-8px) } to { opacity:1; transform:translateY(0) } }`}</style>
    </div>
  );
}

